// lib/core/constants/user_images.dart
import 'dart:typed_data';
import 'dart:convert';

class UserImages {
  static final Map<String, Uint8List> _images = {
    'yasser': base64Decode(''),
    'osama': base64Decode(''),
    'mohanad': base64Decode(''),
    'moaz': base64Decode(''),
    'nadeem': base64Decode(''),
    'basmalah': base64Decode(''),
    'manar': base64Decode(''),
  };

  static final Map<String, String> _uidMap = {
    '220423':        'yasser',
    '221798':        'osama',
    '223012':        'mohanad',
    '222072':        'moaz',
    '221730':        'nadeem',
    '221037':        'basmalah',
    '221737':        'manar',
    'doctor_omaima': 'omaima',
  };

  static Uint8List? getImageBytes(String? firebaseUid) {
    if (firebaseUid == null) return null;
    final key = _uidMap[firebaseUid];
    if (key == null) return null;
    return _images[key];
  }
}
